INSERT INTO examples (name, category, framework, files, dependencies, metadata) VALUES ('"css-reset"', '"Prsnt"', '"vanilla"', '{"demo.css": "html {\n  max-width: 70ch;\n  margin: auto;\n  padding: 3em 1em;\n  font-family: system-ui, ''Segoe UI'', Roboto, Cantarell,\n    ''Helvetica Neue'', Helvetica, Arial, sans-serif;\n  font-size: 1.25em;\n  line-height: 1.75;\n}\n\nbody {\n  margin: 0;\n}\n\nh1, h2, h3, h4, h5, h6 {\n  margin: 3em 0 1em;\n}\n\np, ul, ol {\n  margin-bottom: 2em;\n  color: #1d1d1d;\n}\n\nsmall {\n  font-size: 80%;\n}\n\nsub, sup {\n  font-size: 75%;\n  line-height: 0;\n  position: relative;\n  vertical-align: baseline;\n}\n\nsub {\n  bottom: -0.25em;\n}\n\nsup {\n  top: -0.5em;\n}\n\npre, code, kbd {\n  font-family: monospace, monospace;\n  font-size: 1em;\n}\n", "demo.html": "<!DOCTYPE html>\r\n<html lang=\"en\">\r\n  <head>\r\n    <meta charset=\"UTF-8\" />\r\n    <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\" />\r\n    <meta http-equiv=\"X-UA-Compatible\" content=\"ie=edge\" />\r\n    <link rel=\"stylesheet\" href=\"style.css\" />\r\n    <title>Static Template</title>\r\n  </head>\r\n  <body>\r\n    <h1>\r\n      CSS Reset\r\n    </h1>\r\n    <script src=\"script.js\"></script>\r\n  </body>\r\n</html>\r\n"}', '{}', '{"original_path": "Vanilla/Prsnt/Functionality/css-reset"}'), ('"etched-text"', '"Prsnt"', '"vanilla"', '{"demo.css": ".etched-text {\n  text-shadow: 0 2px white;\n  font-size: 1.5rem;\n  font-weight: bold;\n  color: #b8bec5;\n}\n", "demo.html": "<!DOCTYPE html>\r\n<html lang=\"en\">\r\n  <head>\r\n    <meta charset=\"UTF-8\" />\r\n    <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\" />\r\n    <meta http-equiv=\"X-UA-Compatible\" content=\"ie=edge\" />\r\n    <link rel=\"stylesheet\" href=\"style.css\" />\r\n    <title>Static Template</title>\r\n  </head>\r\n  <body>\r\n    <h1>\r\n      Etched text\r\n    </h1>\r\n    <p class=\"etched-text\">I appear etched into the background.</p>\r\n\r\n    <script src=\"script.js\"></script>\r\n  </body>\r\n</html>\r\n"}', '{}', '{"original_path": "Vanilla/Prsnt/Functionality/etched-text"}'), ('"fallback-for-images-that-fail-to-load"', '"Prsnt"', '"vanilla"', '{"demo.css": "img {\n  display: block;\n  font-family: sans-serif;\n  font-weight: 300;\n  height: auto;\n  line-height: 2;\n  position: relative;\n  text-align: center;\n  width: 100%;\n}\n\nimg::before {\n  content: \"Sorry, this image is unavailable.\";\n  display: block;\n  margin-bottom: 8px;\n}\n\nimg::after {\n  content: \"(url: \" attr(src) \")\";\n  display: block;\n  font-size: 12px;\n}\n", "demo.html": "<!DOCTYPE html>\r\n<html lang=\"en\">\r\n  <head>\r\n    <meta charset=\"UTF-8\" />\r\n    <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\" />\r\n    <meta http-equiv=\"X-UA-Compatible\" content=\"ie=edge\" />\r\n    <link rel=\"stylesheet\" href=\"style.css\" />\r\n    <title>Static Template</title>\r\n  </head>\r\n  <body>\r\n    <h1>\r\n      Fallback for images that fail to load\r\n    </h1>\r\n    <img src=\"https://nowhere.to.be/found.jpg\" />\r\n\r\n    <script src=\"script.js\"></script>\r\n  </body>\r\n</html>\r\n"}', '{}', '{"original_path": "Vanilla/Prsnt/Functionality/fallback-for-images-that-fail-to-load"}'), ('"focus-within"', '"Prsnt"', '"vanilla"', '{"demo.css": "form {\n  border: 2px solid #52B882;\n  padding: 8px;\n  border-radius: 2px;\n}\n\nform:focus-within {\n  background: #7CF0BD;\n}\n\nlabel {\n  display: inline-block;\n  width: 72px;\n}\n\ninput {\n  margin: 4px 12px;\n}\n", "demo.html": "<!DOCTYPE html>\r\n<html lang=\"en\">\r\n  <head>\r\n    <meta charset=\"UTF-8\" />\r\n    <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\" />\r\n    <meta http-equiv=\"X-UA-Compatible\" content=\"ie=edge\" />\r\n    <link rel=\"stylesheet\" href=\"style.css\" />\r\n    <title>Static Template</title>\r\n  </head>\r\n  <body>\r\n    <h1>\r\n      Focus Within\r\n    </h1>\r\n    <form>\r\n      <label for=\"username\">Username:</label>\r\n      <input id=\"username\" type=\"text\" />\r\n      <br />\r\n      <label for=\"password\">Password:</label>\r\n      <input id=\"password\" type=\"text\" />\r\n    </form>\r\n\r\n    <script src=\"script.js\"></script>\r\n  </body>\r\n</html>\r\n"}', '{}', '{"original_path": "Vanilla/Prsnt/Functionality/focus-within"}'), ('"fullscreen"', '"Prsnt"', '"vanilla"', '{"demo.css": ".container {\n  margin: 40px auto;\n  max-width: 700px;\n}\n\n.element {\n  padding: 20px;\n  height: 300px;\n  width: 100%;\n  background-color: skyblue;\n  box-sizing: border-box;\n}\n\n.element p {\n  text-align: center;\n  color: white;\n  font-size: 3em;\n}\n\n.element:-ms-fullscreen p {\n  visibility: visible;\n}\n\n.element:fullscreen {\n  background-color: #e4708a;\n  width: 100vw;\n  height: 100vh;\n}\n", "demo.html": "<!DOCTYPE html>\r\n<html lang=\"en\">\r\n  <head>\r\n    <meta charset=\"UTF-8\" />\r\n    <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\" />\r\n    <meta http-equiv=\"X-UA-Compatible\" content=\"ie=edge\" />\r\n    <link rel=\"stylesheet\" href=\"style.css\" />\r\n    <title>Static Template</title>\r\n  </head>\r\n  <body>\r\n    <h1>\r\n      Fullscreen\r\n    </h1>\r\n    <div class=\"container\">\r\n      <p>\r\n        <em\r\n          >Click the button below to enter the element into fullscreen mode.\r\n        </em>\r\n      </p>\r\n      <div class=\"element\" id=\"element\">\r\n        <p>I change color in fullscreen mode!</p>\r\n      </div>\r\n      <br />\r\n      <button\r\n        onclick=\"var el = document.getElementById(''element''); el.requestFullscreen();\"\r\n      >\r\n        Go Full Screen!\r\n      </button>\r\n    </div>\r\n\r\n    <script src=\"script.js\"></script>\r\n  </body>\r\n</html>\r\n"}', '{}', '{"original_path": "Vanilla/Prsnt/Functionality/fullscreen"}'), ('"hide-empty-elements"', '"Prsnt"', '"vanilla"', '{"demo.css": ":empty {\n  display: none;\n}\n", "demo.html": "<!DOCTYPE html>\r\n<html lang=\"en\">\r\n  <head>\r\n    <meta charset=\"UTF-8\" />\r\n    <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\" />\r\n    <meta http-equiv=\"X-UA-Compatible\" content=\"ie=edge\" />\r\n    <link rel=\"stylesheet\" href=\"style.css\" />\r\n    <title>Static Template</title>\r\n  </head>\r\n  <body>\r\n    <h1>\r\n      Hide empty elements\r\n    </h1>\r\n    <p>Lorem ipsum dolor sit amet. <button></button></p>\r\n\r\n    <script src=\"script.js\"></script>\r\n  </body>\r\n</html>\r\n"}', '{}', '{"original_path": "Vanilla/Prsnt/Functionality/hide-empty-elements"}'), ('"hide-scroll-bars"', '"Prsnt"', '"vanilla"', '{"demo.css": "div {\n  width: 200px;\n  height: 100px;\n}\n\n.no-scrollbars {\n  overflow: auto;\n  scrollbar-width: none;\n}\n\n.no-scrollbars::-webkit-scrollbar {\n  display: none;\n}\n", "demo.html": "<!DOCTYPE html>\r\n<html lang=\"en\">\r\n  <head>\r\n    <meta charset=\"UTF-8\" />\r\n    <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\" />\r\n    <meta http-equiv=\"X-UA-Compatible\" content=\"ie=edge\" />\r\n    <link rel=\"stylesheet\" href=\"style.css\" />\r\n    <title>Static Template</title>\r\n  </head>\r\n  <body>\r\n    <h1>\r\n      Hide scroll bars\r\n    </h1>\r\n    <div class=\"no-scrollbars\">\r\n      <p>\r\n        Lorem ipsum dolor sit amet, consectetur adipiscing elit. Aenean interdum\r\n        id leo a consectetur. Integer justo magna, ultricies vel enim vitae,\r\n        egestas efficitur leo. Ut nulla orci, rutrum eu augue sed, tempus\r\n        pellentesque quam.\r\n      </p>\r\n    </div>\r\n\r\n    <script src=\"script.js\"></script>\r\n  </body>\r\n</html>\r\n"}', '{}', '{"original_path": "Vanilla/Prsnt/Functionality/hide-scroll-bars"}'), ('"horizontal-scroll-snap"', '"Prsnt"', '"vanilla"', '{"demo.css": ".horizontal-snap {\n  margin: 0 auto;\n  display: grid;\n  grid-auto-flow: column;\n  gap: 1rem;\n  height: calc(180px + 1rem);\n  padding: 1rem;\n  max-width: 480px;\n  overflow-y: auto;\n  overscroll-behavior-x: contain;\n  scroll-snap-type: x mandatory;\n}\n\n.horizontal-snap > a {\n  scroll-snap-align: center;\n}\n\n.horizontal-snap img {\n  width: 180px;\n  max-width: none;\n  object-fit: contain;\n  border-radius: 1rem;\n}\n", "demo.html": "<!DOCTYPE html>\r\n<html lang=\"en\">\r\n  <head>\r\n    <meta charset=\"UTF-8\" />\r\n    <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\" />\r\n    <meta http-equiv=\"X-UA-Compatible\" content=\"ie=edge\" />\r\n    <link rel=\"stylesheet\" href=\"style.css\" />\r\n    <title>Static Template</title>\r\n  </head>\r\n  <body>\r\n    <h1>\r\n      Horizontal Scroll Snap\r\n    </h1>\r\n    <div class=\"horizontal-snap\">\r\n      <a href=\"#\"><img src=\"https://picsum.photos/id/1067/640/640\" /></a>\r\n      <a href=\"#\"><img src=\"https://picsum.photos/id/122/640/640\" /></a>\r\n      <a href=\"#\"><img src=\"https://picsum.photos/id/188/640/640\" /></a>\r\n      <a href=\"#\"><img src=\"https://picsum.photos/id/249/640/640\" /></a>\r\n      <a href=\"#\"><img src=\"https://picsum.photos/id/257/640/640\" /></a>\r\n      <a href=\"#\"><img src=\"https://picsum.photos/id/259/640/640\" /></a>\r\n      <a href=\"#\"><img src=\"https://picsum.photos/id/283/640/640\" /></a>\r\n      <a href=\"#\"><img src=\"https://picsum.photos/id/288/640/640\" /></a>\r\n      <a href=\"#\"><img src=\"https://picsum.photos/id/299/640/640\" /></a>\r\n    </div>\r\n\r\n    <script src=\"script.js\"></script>\r\n  </body>\r\n</html>\r\n"}', '{}', '{"original_path": "Vanilla/Prsnt/Functionality/horizontal-scroll-snap"}'), ('"reset-all-styles"', '"Prsnt"', '"vanilla"', '{"demo.css": ".reset-all-styles {\n  all: initial;\n}\n", "demo.html": "<!DOCTYPE html>\r\n<html lang=\"en\">\r\n  <head>\r\n    <meta charset=\"UTF-8\" />\r\n    <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\" />\r\n    <meta http-equiv=\"X-UA-Compatible\" content=\"ie=edge\" />\r\n    <link rel=\"stylesheet\" href=\"style.css\" />\r\n    <title>Static Template</title>\r\n  </head>\r\n  <body>\r\n    <h1>\r\n      Reset all styles\r\n    </h1>\r\n    <div class=\"reset-all-styles\">\r\n      <h5>Title</h5>\r\n      <p>\r\n        Lorem ipsum dolor sit amet consectetur adipisicing elit. Iure id\r\n        exercitationem nulla qui repellat laborum vitae, molestias tempora velit\r\n        natus. Quas, assumenda nisi. Quisquam enim qui iure, consequatur velit\r\n        sit?\r\n      </p>\r\n    </div>\r\n\r\n    <script src=\"script.js\"></script>\r\n  </body>\r\n</html>\r\n"}', '{}', '{"original_path": "Vanilla/Prsnt/Functionality/reset-all-styles"}'), ('"show-additional-content-on-hover"', '"Prsnt"', '"vanilla"', '{"demo.css": ".card {\n  width: 300px;\n  height: 280px;\n  padding: 0;\n  box-shadow: 0 2px 4px 0 rgba(0,0,0,0.1);\n  border-radius: 8px;\n  box-sizing: border-box;\n  overflow: hidden;\n}\n\n.card * {\n  transition: 0.3s ease all;\n}\n\n.card img {\n  margin: 0;\n  width: 300px;\n  height: 224px;\n  object-fit: cover;\n  display: block;\n}\n\n.card h3 {\n  margin: 0;\n  padding: 12px 12px 48px;\n  line-height: 32px;\n  font-weight: 500;\n  font-size: 20px;\n}\n\n.card .focus-content {\n  display: block;\n  padding: 8px 12px;\n}\n\n.card p {\n  margin: 0;\n  line-height: 1.5;\n}\n\n.card:hover img, .card:focus-within img {\n  margin-top: -80px;\n}\n\n.card:hover h3, .card:focus-within h3 {\n  padding: 8px 12px 0;\n}\n", "demo.html": "<!DOCTYPE html>\r\n<html lang=\"en\">\r\n  <head>\r\n    <meta charset=\"UTF-8\" />\r\n    <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\" />\r\n    <meta http-equiv=\"X-UA-Compatible\" content=\"ie=edge\" />\r\n    <link rel=\"stylesheet\" href=\"style.css\" />\r\n    <title>Static Template</title>\r\n  </head>\r\n  <body>\r\n    <h1>\r\n      Show additional content on hover\r\n    </h1>\r\n    <div class=\"card\">\r\n      <img src=\"https://picsum.photos/id/404/367/267\" />\r\n      <h3>Lorem ipsum</h3>\r\n      <div class=\"focus-content\">\r\n        <p>\r\n          Lorem ipsum dolor sit amet, consectetur adipiscing elit.<br />\r\n          <a href=\"#\">Link to source</a>\r\n        </p>\r\n      </div>\r\n    </div>\r\n\r\n    <script src=\"script.js\"></script>\r\n  </body>\r\n</html>\r\n"}', '{}', '{"original_path": "Vanilla/Prsnt/Functionality/show-additional-content-on-hover"}'), ('"sibling-fade"', '"Prsnt"', '"vanilla"', '{"demo.css": "span {\n  padding: 0 16px;\n  transition: opacity 0.3s;\n}\n\n.sibling-fade:hover span:not(:hover) {\n  opacity: 0.5;\n}\n", "demo.html": "<!DOCTYPE html>\r\n<html lang=\"en\">\r\n  <head>\r\n    <meta charset=\"UTF-8\" />\r\n    <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\" />\r\n    <meta http-equiv=\"X-UA-Compatible\" content=\"ie=edge\" />\r\n    <link rel=\"stylesheet\" href=\"style.css\" />\r\n    <title>Static Template</title>\r\n  </head>\r\n  <body>\r\n    <h1>\r\n      Sibling Fade\r\n    </h1>\r\n    <div class=\"sibling-fade\">\r\n      <span>Item 1</span> <span>Item 2</span> <span>Item 3</span>\r\n      <span>Item 4</span> <span>Item 5</span> <span>Item 6</span>\r\n    </div>\r\n\r\n    <script src=\"script.js\"></script>\r\n  </body>\r\n</html>\r\n"}', '{}', '{"original_path": "Vanilla/Prsnt/Functionality/sibling-fade"}'), ('"system-font-stack"', '"Prsnt"', '"vanilla"', '{"demo.css": ".system-font-stack {\n  font-family: -apple-system, BlinkMacSystemFont, ''Segoe UI'', Roboto,\n    Oxygen-Sans, Ubuntu, Cantarell, ''Helvetica Neue'', Helvetica, Arial,\n    sans-serif;\n}\n", "demo.html": "<!DOCTYPE html>\r\n<html lang=\"en\">\r\n  <head>\r\n    <meta charset=\"UTF-8\" />\r\n    <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\" />\r\n    <meta http-equiv=\"X-UA-Compatible\" content=\"ie=edge\" />\r\n    <link rel=\"stylesheet\" href=\"style.css\" />\r\n    <title>Static Template</title>\r\n  </head>\r\n  <body>\r\n    <h1>\r\n      System font stack\r\n    </h1>\r\n    <p class=\"system-font-stack\">This text uses the system font.</p>\r\n\r\n    <script src=\"script.js\"></script>\r\n  </body>\r\n</html>\r\n"}', '{}', '{"original_path": "Vanilla/Prsnt/Functionality/system-font-stack"}'), ('"the-currentcolor-css-keyword"', '"Prsnt"', '"vanilla"', '{"demo.css": "p {\n  color: #101010;\n}\n\np, p > * {\n  background-color: currentColor;\n}\n\na {\n  color: #0077ff;\n}\n\nspan {\n  color: #fd203a;\n}\n", "demo.html": "<!DOCTYPE html>\r\n<html lang=\"en\">\r\n  <head>\r\n    <meta charset=\"UTF-8\" />\r\n    <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\" />\r\n    <meta http-equiv=\"X-UA-Compatible\" content=\"ie=edge\" />\r\n    <link rel=\"stylesheet\" href=\"style.css\" />\r\n    <title>Static Template</title>\r\n  </head>\r\n  <body>\r\n    <h1>\r\n      The currentColor CSS keyword\r\n    </h1>\r\n    <p>\r\n      My <span>background</span> is the same color as my <a href=\"#\">text</a>.\r\n    </p>\r\n\r\n    <script src=\"script.js\"></script>\r\n  </body>\r\n</html>\r\n"}', '{}', '{"original_path": "Vanilla/Prsnt/Functionality/the-currentcolor-css-keyword"}'), ('"vertical-scroll-snap"', '"Prsnt"', '"vanilla"', '{"demo.css": ".vertical-snap {\n  margin: 0 auto;\n  display: grid;\n  grid-auto-flow: row;\n  gap: 1rem;\n  width: calc(180px + 1rem);\n  padding: 1rem;\n  height: 480px;\n  overflow-y: auto;\n  overscroll-behavior-y: contain;\n  scroll-snap-type: y mandatory;\n}\n\n.vertical-snap > a {\n  scroll-snap-align: center;\n}\n\n.vertical-snap img {\n  width: 180px;\n  object-fit: contain;\n  border-radius: 1rem;\n}\n", "demo.html": "<!DOCTYPE html>\r\n<html lang=\"en\">\r\n  <head>\r\n    <meta charset=\"UTF-8\" />\r\n    <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\" />\r\n    <meta http-equiv=\"X-UA-Compatible\" content=\"ie=edge\" />\r\n    <link rel=\"stylesheet\" href=\"style.css\" />\r\n    <title>Stati