/>\r\n    <title>Static Template</title>\r\n  </head>\r\n  <body>\r\n    <h1>\r\n      Auto Complete\r\n    </h1>\r\n    <!-- https://vanillajstoolkit.com/reference/javascript-free/autocomplete/ -->\r\n\r\n    <label for=\"states\">Who''s the best wizard?</label>\r\n    <input type=\"text\" id=\"wizards\" name=\"wizards\" list=\"wizards-list\" />\r\n    <datalist id=\"wizards-list\">\r\n      <option>Harry Potter</option>\r\n      <option>Hermione</option>\r\n      <option>Dumbledore</option>\r\n      <option>Merlin</option>\r\n      <option>Gandalf</option>\r\n    </datalist>\r\n\r\n    <script src=\"script.js\"></script>\r\n  </body>\r\n</html>\r\n"}', '{}', '{"original_path": "Vanilla/Prsnt/Input/auto-complete"}'), ('"box-selector"', '"Prsnt"', '"vanilla"', '{"demo.css": ".box-selector {\n  border: 1px solid #d1d5db;\n  border-radius: 0.25rem;\n  padding: 0.5rem;\n}\n\n.box-selector--selected {\n  /* Change the border color */\n  border: 2px solid #3b82f6;\n\n  /* Used to position the tick */\n  position: relative;\n}\n\n/* The tick */\n.box-selector--selected:before {\n  /* Absolute position */\n  content: \"\";\n  left: 0.25rem;\n  position: absolute;\n  top: 0.25rem;\n\n  /* Size */\n  height: 1rem;\n  width: 1rem;\n\n  /* Background */\n  background-image: url(\"data:image/svg+xml,%3Csvg fill=''%233b82f6'' xmlns=''http://www.w3.org/2000/svg'' viewBox=''0 0 24 24'' %3E%3Cpath d=''M12 2C6.48 2 2 6.48 2 12s4.48 10 10 10 10-4.48 10-10S17.52 2 12 2zm-2 15l-5-5 1.41-1.41L10 14.17l7.59-7.59L19 8l-9 9z''%3E%3C/path%3E%3C/svg%3E\");\n  background-position: center center;\n  background-repeat: no-repeat;\n}\n", "demo.html": "<!DOCTYPE html>\r\n<html lang=\"en\">\r\n  <head>\r\n    <meta charset=\"UTF-8\" />\r\n    <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\" />\r\n    <meta http-equiv=\"X-UA-Compatible\" content=\"ie=edge\" />\r\n    <link rel=\"stylesheet\" href=\"style.css\" />\r\n    <title>Static Template</title>\r\n  </head>\r\n  <body>\r\n    <h1>\r\n      Box Selector\r\n    </h1>\r\n    <div class=\"box-selector\">default</div>\r\n\r\n    <!-- The selected variant -->\r\n    <div class=\"box-selector box-selector--selected\">Selected</div>\r\n\r\n    <script src=\"script.js\"></script>\r\n  </body>\r\n</html>\r\n"}', '{}', '{"original_path": "Vanilla/Prsnt/Input/box-selector"}'), ('"button-with-icon"', '"Prsnt"', '"vanilla"', '{"demo.css": ".button-with-icon {\n  /* Center the content */\n  align-items: center;\n  display: flex;\n  flex-direction: row;\n  justify-content: center;\n}\n\n.button-with-icon__label {\n  margin-left: 0.5rem;\n}\n", "demo.html": "<!DOCTYPE html>\r\n<html lang=\"en\">\r\n  <head>\r\n    <meta charset=\"UTF-8\" />\r\n    <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\" />\r\n    <meta http-equiv=\"X-UA-Compatible\" content=\"ie=edge\" />\r\n    <link rel=\"stylesheet\" href=\"style.css\" />\r\n    <title>Static Template</title>\r\n  </head>\r\n  <body>\r\n    <h1>\r\n      Button with icon\r\n    </h1>\r\n    <button class=\"button-with-icon\">\r\n      <!-- Icon -->\r\n      Icon\r\n\r\n      <!-- Label -->\r\n      <div class=\"button-with-icon__label\">Label</div>\r\n    </button>\r\n\r\n    <script src=\"script.js\"></script>\r\n  </body>\r\n</html>\r\n"}', '{}', '{"original_path": "Vanilla/Prsnt/Input/button-with-icon"}'), ('"chip"', '"Prsnt"', '"vanilla"', '{"demo.css": ".chip {\n  /* Center the content */\n  align-items: center;\n  display: inline-flex;\n  justify-content: center;\n\n  /* Background color */\n  background-color: #d1d5db;\n\n  /* Rounded border */\n  border-radius: 9999px;\n\n  /* Spacing */\n  padding: 0.25rem 0.5rem;\n}\n\n.chip__content {\n  margin-right: 0.25rem;\n}\n\n/* The close button is used to create a button for removing the chip: */\n.chip__button {\n  /* Reset */\n  background-color: transparent;\n  border-color: transparent;\n\n  /* Cursor */\n  cursor: pointer;\n\n  /* Size */\n  height: 1rem;\n  width: 1rem;\n\n  /* Used to position the inner */\n  position: relative;\n}\n\n.chip__button-line {\n  /* Background color */\n  background-color: #9ca3af;\n\n  /* Position */\n  position: absolute;\n\n  /* Size */\n  height: 1px;\n  width: 100%;\n}\n\n.chip__button-line--first {\n  /* Position */\n  left: 0px;\n  top: 50%;\n  transform: translate(0%, -50%) rotate(45deg);\n\n  /* Size */\n  height: 1px;\n  width: 100%;\n}\n\n.chip__button-line--second {\n  /* Position */\n  left: 50%;\n  top: 0px;\n  transform: translate(-50%, 0%) rotate(45deg);\n\n  /* Size */\n  height: 100%;\n  width: 1px;\n}\n", "demo.html": "<!DOCTYPE html>\r\n<html lang=\"en\">\r\n  <head>\r\n    <meta charset=\"UTF-8\" />\r\n    <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\" />\r\n    <meta http-equiv=\"X-UA-Compatible\" content=\"ie=edge\" />\r\n    <link rel=\"stylesheet\" href=\"style.css\" />\r\n    <title>Static Template</title>\r\n  </head>\r\n  <body>\r\n    <h1>\r\n      Chip\r\n    </h1>\r\n    <div class=\"chip\">\r\n      <!-- Content -->\r\n      <div class=\"chip__content\">tag1</div>\r\n\r\n      <!-- The close button -->\r\n      <button class=\"chip__button\">\r\n        <div class=\"chip__button-line chip__button-line--first\"></div>\r\n        <div class=\"chip__button-line chip__button-line--second\"></div>\r\n      </button>\r\n    </div>\r\n\r\n    <script src=\"script.js\"></script>\r\n  </body>\r\n</html>\r\n"}', '{}', '{"original_path": "Vanilla/Prsnt/Input/chip"}'), ('"custom-checkbox-button"', '"Prsnt"', '"vanilla"', '{"demo.css": ".custom-checkbox-button {\n  /* Center the content horizontally */\n  align-items: center;\n  display: inline-flex;\n\n  /* Cursor */\n  cursor: pointer;\n}\n\n.custom-checkbox-button__input {\n  /* Hide it */\n  display: none;\n}\n\n.custom-checkbox-button__square {\n  border: 1px solid #d1d5db;\n  border-radius: 0.25rem;\n\n  /* Spacing */\n  margin-right: 0.5rem;\n  padding: 0.25rem;\n}\n\n.custom-checkbox-button__checkbox {\n  background-color: transparent;\n  border-radius: 0.25rem;\n  height: 1rem;\n  width: 1rem;\n}\n\n.custom-checkbox-button__checkbox--selected {\n  /* For selected checkbox */\n  background-color: #3b82f6;\n}\n", "demo.html": "<!DOCTYPE html>\r\n<html lang=\"en\">\r\n  <head>\r\n    <meta charset=\"UTF-8\" />\r\n    <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\" />\r\n    <meta http-equiv=\"X-UA-Compatible\" content=\"ie=edge\" />\r\n    <link rel=\"stylesheet\" href=\"style.css\" />\r\n    <title>Custom Checkbox Button</title>\r\n  </head>\r\n  <body>\r\n    <h1>\r\n      Static Template\r\n    </h1>\r\n    <label class=\"custom-checkbox-button\">\r\n      <!-- The real checkbox -->\r\n      <input type=\"checkbox\" class=\"custom-checkbox-button__input\" />\r\n\r\n      <!-- The fake square -->\r\n      <div class=\"custom-checkbox-button__square\">\r\n        <!-- The inner square -->\r\n        <div\r\n          class=\"custom-checkbox-button__checkbox custom-checkbox-button__checkbox--selected\"\r\n        ></div>\r\n      </div>\r\n\r\n      <!-- The text -->\r\n      Option 1\r\n    </label>\r\n\r\n    <script src=\"script.js\"></script>\r\n  </body>\r\n</html>\r\n"}', '{}', '{"original_path": "Vanilla/Prsnt/Input/custom-checkbox-button"}'), ('"custom-radio-button"', '"Prsnt"', '"vanilla"', '{"demo.css": ".custom-radio-button {\n  /* Center the content horizontally */\n  align-items: center;\n  display: inline-flex;\n\n  /* Cursor */\n  cursor: pointer;\n}\n\n.custom-radio-button__input {\n  /* Hide it */\n  display: none;\n}\n\n.custom-radio-button__circle {\n  /* Rounded border */\n  border: 1px solid #d1d5db;\n  border-radius: 9999px;\n\n  /* Spacing */\n  margin-right: 0.5rem;\n  padding: 0.25rem;\n}\n\n.custom-radio-button__radio {\n  /* Rounded border */\n  border-radius: 9999px;\n  height: 1rem;\n  width: 1rem;\n\n  /* For not selected radio */\n  background-color: transparent;\n}\n\n.custom-radio-button__radio--selected {\n  /* For selected radio */\n  background-color: #3b82f6;\n}\n", "demo.html": "<!DOCTYPE html>\r\n<html lang=\"en\">\r\n  <head>\r\n    <meta charset=\"UTF-8\" />\r\n    <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\" />\r\n    <meta http-equiv=\"X-UA-Compatible\" content=\"ie=edge\" />\r\n    <link rel=\"stylesheet\" href=\"style.css\" />\r\n    <title>Static Template</title>\r\n  </head>\r\n  <body>\r\n    <h1>\r\n      Custom Radio Button\r\n    </h1>\r\n    <label class=\"custom-radio-button\">\r\n      <!-- The real radio -->\r\n      <input type=\"radio\" class=\"custom-radio-button__input\" />\r\n\r\n      <!-- The fake circle -->\r\n      <div class=\"custom-radio-button__circle\">\r\n        <!-- The inner circle -->\r\n        <div\r\n          class=\"custom-radio-button__radio custom-radio-button__radio--selected\"\r\n        ></div>\r\n      </div>\r\n\r\n      <!-- The text -->\r\n      Option 1\r\n    </label>\r\n\r\n    <script src=\"script.js\"></script>\r\n  </body>\r\n</html>\r\n"}', '{}', '{"original_path": "Vanilla/Prsnt/Input/custom-radio-button"}');